module RefModule (  
    input [4:0] data_in,  
    input clk,  
    output reg [5:0] data_out  
);  
    reg [5:0] unused_stage1_out;  

    always @(posedge clk) begin  
        // Stage 1: Addition  
        unused_stage1_out <= data_in + 5'b00001;  
    end  

    always @(posedge clk) begin  
        // Stage 2: Multiplication by 3  
        data_out <= unused_stage1_out * 6'd3;  
    end  
endmodule
